-- =============================================================================
-- 02_data_import_sample.sql
-- Decision Intelligence System — Bulk data load (SAMPLE)
-- -----------------------------------------------------------------------------
-- Purpose : Reduced-size replacement for 02_data_import.sql. Same schema,
--           same COPY structure, referentially consistent subset of the data.
-- Run order: 2nd (in place of 02_data_import.sql). Requires 01_database_schema.sql.
--
-- Sampling method:
--   * Reference / cost tables kept in full (71 rows each).
--   * orders          -> every 20th row (~4973 sampled orders).
--   * order_items     -> rows for the sampled orders only.
--   * order_reviews   -> rows for the sampled orders only.
--   * products        -> only products actually referenced by sampled items.
--   * forecast_results-> all category-grain rows + sku-grain rows for the
--                        sampled products.
--
-- Referential integrity: every order_item points at a sampled order AND a
-- kept product; every review points at a sampled order; every category cost
-- row is present so 03_data_cleaning.sql's coverage-assert still passes.
-- =============================================================================

SET client_encoding = 'UTF8';
SET standard_conforming_strings = on;
SET client_min_messages = warning;











